// ===== Smart Normalization (optimized) =====

// Column name mapping rules
const columnMap = {
  "full name": "name",
  "email address": "email",
  "phone no": "phone",
  "amount ($)": "amount",
};

// Default schema template
const defaultSchema = {
  name: null,
  email: null,
  phone: null,
  amount: null,
  source_file: $json.filename || null,
  processed_at: new Date().toISOString(),
};

let normalized = {};

// Normalize each key/value
for (let [key, value] of Object.entries($json)) {

  // Key normalization: trim → lowercase → strip symbols → replace spaces with _
  let cleanKey = key.trim().toLowerCase()
    .replace(/[^a-z0-9 ]/g, "")
    .replace(/\s+/g, "_");

  // Apply mapping
  cleanKey = columnMap[cleanKey] || cleanKey;

  // Value normalization
  value = (value === "" || value === undefined || value === null)
    ? null
    : String(value).trim();

  normalized[cleanKey] = value;
}

// Merge with schema defaults
return { ...defaultSchema, ...normalized };

const items = $input.all();

for (const item of items) {
    let text = item.binary.data.toString('utf8');

    text = text.replace(/\r\n|\r/g, "\n");
    text = text.replace(/[ \t]+/g, " ");
    text = text.replace(/\n{3,}/g, "\n\n");
    text = text.replace(/[\u201c\u201d]/g, '"').replace(/[\u2018\u2019]/g, "'");
    text = text.replace(/[^\x09\x0A\x0D\x20-\x7E]/g, "");
    text = text.split("\n").map(line => line.trim()).join("\n");

    item.json = { content: text };
}

return items;

// Smart TXT Normalization for OCR Extracted Text (Personal AI Factory v1)

const raw = $json.text || "";

// Normalize, clean and format text
const normalized = raw
  .replace(/\r\n/g, "\n")        // Convert CRLF to LF
  .replace(/[ \t]+/g, " ")       // Normalize extra spaces
  .replace(/\n{3,}/g, "\n\n")    // Reduce >2 blank lines to max 1
  .replace(/[^\S\r\n]+/g, " ")   // Trim odd spacing without removing line breaks
  .replace(/\u00A0/g, " ")       // Replace non-breaking spaces
  .trim();

// Optional: remove repeating headers/footer patterns if needed
// Example cleanup for page artifacts:
const finalText = normalized
  .replace(/Page \d+ of \d+/gi, "")
  .replace(/Confidential/gi, "")
  .trim();

return [
  {
    json: {
      text: finalText
    }
  }
];
